const b = $input.all()[0].json;
const cpf    = String(b.cpf || '').replace(/[^0-9]/g, '');
const leadId = b.lead_id || '';
const cep    = String(b.cep || '').replace(/[^0-9]/g, '');

if (cpf.length !== 11) throw new Error('CPF inválido: ' + cpf);
if (!leadId)           throw new Error('lead_id obrigatório');

// Formatar CPF para consulta
const cpfFormatado = cpf.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');

return [{ json: { cpf, cpfFormatado, leadId, cep } }];

// Dados da Receita Federal
const receita = (() => {
  try { return $('Consultar Receita Federal').item.json; }
  catch(e) { return {}; }
})();

// Dados do CEP
const cepData = (() => {
  try { return $('Consultar CEP (BrasilAPI)').item.json; }
  catch(e) { return {}; }
})();

const leadId = $('Validar CPF e Lead').item.json.leadId;

// Situação Receita
const receitaSituacao = receita.situacao || receita.status || 'Não consultado';

// Estimar renda por região (tabela simplificada IBGE por estado)
const RENDA_ESTADO = {
  'GO': 2800, 'SP': 3800, 'RJ': 3200, 'MG': 2600, 'SC': 3100,
  'RS': 3000, 'PR': 2900, 'DF': 4500, 'BA': 2200, 'CE': 1900,
  'PE': 2100, 'AM': 2300, 'PA': 1800
};
const estado = cepData.state || 'GO';
const rendaEstimada = RENDA_ESTADO[estado] || 2500;

// Score simples (heurístico) — substituir por API real
const scoreCredito = receitaSituacao === 'Regular' ? 650 : 450;

return [{ json: {
  leadId,
  receita_situacao:  receitaSituacao,
  renda_estimada:    rendaEstimada,
  score_credito:     scoreCredito,
  cep_regiao:        cepData.city ? `${cepData.city}/${estado}` : estado,
  protestos:         0,
  processos:         0,
  nota: 'protestos e processos requerem acesso IEPTB / PJe-GO'
}}];
